import{_ as i,o as t,c as n,a2 as o}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Intégration & Envoi","description":"","frontmatter":{"title":"Intégration & Envoi"},"headers":[],"relativePath":"docs/fr/publishers/display-email/integration.md","filePath":"docs/fr/publishers/display-email/integration.md"}'),r={name:"docs/fr/publishers/display-email/integration.md"};function l(s,e,a,d,p,u){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="integration-et-diffusion" tabindex="-1">Intégration et Diffusion <a class="header-anchor" href="#integration-et-diffusion" aria-label="Permalink to &quot;Intégration et Diffusion&quot;">​</a></h1><p>Le processus est très rapide. Assurez-vous simplement d&#39;utiliser le bon lien de redirection pour être payé.</p><hr class="my-6"><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3 class="mt-0 text-purple-200">Réception des éléments</h3><p>L&#39;Annonceur vous transmet son visuel (JPG/PNG/GIF).</p><ul><li>Vérifiez que le format correspond à votre emplacement (ex: 600px de large).</li><li>Vérifiez la lisibilité sur mobile.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#d73a49;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">!</div><div><h3 class="mt-0 text-red-200">Récupération du Tracking (Obligatoire)</h3><p>Pour que les clics soient comptabilisés (et rémunérés), vous ne devez <strong>pas</strong> utiliser le lien brut de l&#39;annonceur.</p><div style="background:var(--vp-c-bg-elv);border:2px dashed var(--gi-tint-red-text);padding:20px;border-radius:8px;"><ol class="mb-0"><li>Connectez-vous à <a href="https://app.getinside.media/">app.getinside.media</a>.</li><li>Allez dans l&#39;onglet <strong>&quot;Configuration et suivi&quot;</strong> de la campagne.</li><li>Copiez le <strong>&quot;Lien tracké&quot;</strong> unique (format <code>https://gtinsi.de/...</code>).</li></ol></div><p class="mt-3 text-grey-dk-000 fs-2"><em>Note : Contrairement à l&#39;email dédié, il n&#39;y a pas de &quot;Pixel d&#39;ouverture&quot; à installer ici. Seuls les clics comptent.</em></p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">3</div><div><h3 class="mt-0 text-purple-200">Insertion dans votre routeur</h3><p>Dans votre outil d&#39;emailing habituel (Mailchimp, Brevo, Klaviyo...) :</p><ol><li>Insérez l&#39;image de l&#39;annonceur à l&#39;endroit prévu.</li><li>Ajoutez un lien sur cette image.</li><li><strong>Collez le lien tracké</strong> <code>gtinsi.de</code> comme URL de destination.</li></ol></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-tint-green-text);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🚀</div><div><h3 class="mt-0 text-green-200">Validation &amp; Diffusion</h3><p>Dernière ligne droite :</p><ul><li>Envoyez un email de test à <code>benoit+news@getinside.fr</code> pour validation.</li><li>Sur la plateforme, cliquez sur <strong>&quot;Valider la campagne&quot;</strong>.</li><li>Une fois l&#39;envoi terminé, revenez cliquer sur <strong>&quot;Valider la diffusion&quot;</strong> pour déclencher la facturation.</li></ul></div></div>',7)])])}const m=i(r,[["render",l]]);export{g as __pageData,m as default};
